// LoadDriver loads the bookingEntry's Driver into the .R struct
func (o *BookingEntry) LoadDriver(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Driver = nil

	related, err := o.Driver(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.BookingEntries = BookingEntrySlice{o}

	o.R.Driver = related
	return nil
}

// LoadDriver loads the bookingEntry's Driver into the .R struct
func (os BookingEntrySlice) LoadDriver(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	drivers, err := os.Driver(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range drivers {
			if !o.DriverID.IsValue() {
				continue
			}

			if !(o.DriverID.IsValue() && o.DriverID.MustGet() == rel.ID) {
				continue
			}

			rel.R.BookingEntries = append(rel.R.BookingEntries, o)

			o.R.Driver = rel
			break
		}
	}

	return nil
}

